UPDATE supplier_visit_record
supplier_number = #{supplierNumber}, visit_time = #{visitTime}, visitor = #{visitor}, visit_content = #{visitContent}, attachment = #{attachment}, created_by = #{createdBy}, created_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT
    id, supplier_number, visit_time, visitor, visit_content, attachment, created_by, created_at
FROM supplier_visit_record

    AND id = #{id}
    AND supplier_number = #{supplierNumber}
    AND visit_time = #{visitTime}
    AND visitor LIKE CONCAT('%', #{visitor}, '%')
    AND visit_content LIKE CONCAT('%', #{visitContent}, '%')
    AND attachment LIKE CONCAT('%', #{attachment}, '%')
    AND created_by LIKE CONCAT('%', #{createdBy}, '%')
    AND created_at = #{createdAt}

ORDER BY created_at DESC
